.hero-bg { position: absolute; inset: 0; will-change: transform; } /* 배경 줌 */
.r { opacity: 0; will-change: opacity, transform; }              /* 진입 대상 */
/* 모션은 CSS transition이 아니라 JS가 progress에 직접 매핑한다 */

var items = document.querySelectorAll(".r");
var bg = document.querySelector(".hero-bg");
function applyReveal(p){            // p = 스크롤 진행률 0~1
  items.forEach(function(el){
    var i = +el.dataset.i;
    var s = 0.08 + i * 0.11;
    var lp = seg(p, s, s + 0.16);    // 요소별 진입 윈도
    el.style.opacity = lp;
    el.style.transform = "translateX(" + (40 * (1 - lp)) + "px)";
  });
  bg.style.transform = "scale(" + (1.12 - 0.12 * seg(p, 0, 0.6)) + ")";
}
// seg(p,a,b) = clamp01((p-a)/(b-a)) — 구간 정규화 헬퍼

.cr-panel { position: absolute; inset: 0;
  background: rgba(255,255,255,0.72);   /* 반투명 가림막 */
  will-change: transform; }

var panels = document.querySelectorAll(".cr-panel");
function applyReveal(p){
  panels.forEach(function(el, i){
    var s = 0.12 + i * 0.15;            // 패널마다 윈도를 어긋나게
    var lp = seg(p, s, s + 0.2);
    el.style.transform = "translateY(" + (-110 * lp) + "%)"; // 위로 벗기기
  });
}

.wm-word { position: absolute; font-size: 18vw; opacity: 0;
  pointer-events: none; z-index: 0; will-change: opacity, transform; }
.wm-grid { position: relative; z-index: 2; } /* 전경 카드가 글자 위로 */

var word = document.querySelector(".wm-word");
var cards = document.querySelectorAll(".wm-card");
var starts = [0.15, 0.3, 0.45, 0.6];
function applyReveal(p){
  word.style.opacity = seg(p, 0, 0.35) * 0.14;          // 배경: 0→0.14
  word.style.transform = "translateY(" + (8*(1-seg(p,0,0.5))) + "vh)";
  cards.forEach(function(c, i){
    var lp = seg(p, starts[i], starts[i] + 0.3);         // 전경: 카드별 시차
    c.style.opacity = lp;
    c.style.transform = "translateY(" + (36*(1-lp)) + "vh)"; // 이동량 ×4 = 깊이
  });
}

.sp-col { position: relative; flex: 1; height: 100%; overflow: hidden; }
.sp-track { position: absolute; inset: 0 0 auto; will-change: transform; }
.sp-item { height: 100vh; }
.sp-left .sp-track { transform: translateY(-66.66%); } /* 초기: 아래 장면 */

var L = document.querySelector(".sp-left .sp-track");
var R = document.querySelector(".sp-right .sp-track");
function applyReveal(p){              // 같은 p, 반대 부호
  L.style.transform = "translateY(" + (-66.66 * (1 - p)) + "%)"; // 아래로
  R.style.transform = "translateY(" + (-66.66 * p) + "%)";       // 위로
}

.pf-wrap { display: grid; grid-template-columns: 0.9fr 1.1fr; } /* 무대가 sticky → 좌측 자연 고정 */
.pf-card { background: rgba(255,255,255,0.06);
  backdrop-filter: blur(8px); border: 1px solid rgba(255,255,255,0.12); }

var cards = document.querySelectorAll(".pf-card");
function applyReveal(p){
  cards.forEach(function(c, i){
    var s = 0.1 + i * 0.18;             // 카드별 진입 시점
    var lp = seg(p, s, s + 0.25);
    c.style.opacity = 0.25 + 0.75 * lp;
    c.style.transform =
      "translateY(" + ((80*(1-lp)) - 40*seg(p, s+0.25, 1)) + "px)"; // 진입 후 떠밀림
  });
}

.hf-bg { position: absolute; inset: 0; opacity: 0; transition: opacity 200ms ease; }
.hf-bg.is-on { opacity: 1; }
.hf-item { opacity: 0.28; transition: opacity 200ms ease; } /* 비활성 디밍 */
.hf-item.is-on { opacity: 1; }

var items = document.querySelectorAll(".hf-item");
var bgs = document.querySelectorAll(".hf-bg");
function focus(n){
  items.forEach(function(el, i){ el.classList.toggle("is-on", i === n); });
  bgs.forEach(function(el, i){ el.classList.toggle("is-on", i === n); });
}
items.forEach(function(el, i){
  el.addEventListener("mouseenter", function(){ focus(i); });
  el.addEventListener("click", function(){ focus(i); }); // 터치 폴백
});

.tm-slide { position: absolute; inset: 0; opacity: 0; transition: opacity 200ms ease; }
.tm-slide.is-on { opacity: 1; }
.tm-thumb.is-on { border-color: #5cc8ff; transform: scale(1.04); }
.tm-fill { transition: width 200ms ease; }

var slides = document.querySelectorAll(".tm-slide");
var thumbs = document.querySelectorAll(".tm-thumb");
var count = document.querySelector(".tm-count");
var fill = document.querySelector(".tm-fill");
var N = slides.length;
function go(n){                          // 단일 idx → 전 레이어 동기
  slides.forEach(function(s, i){ s.classList.toggle("is-on", i === n); });
  thumbs.forEach(function(t, i){ t.classList.toggle("is-on", i === n); });
  count.textContent = ("0" + (n + 1)).slice(-2);
  fill.style.width = ((n + 1) / N * 100) + "%";
}
thumbs.forEach(function(t, i){ t.addEventListener("click", function(){ go(i); }); });

var fill = document.querySelector(".tl-fill");
var items = document.querySelectorAll(".tl-item");
var N = items.length;
function applyReveal(p){
  fill.style.transform = "scaleY(" + p + ")";        // 축이 자란다
  items.forEach(function(el, i){
    var th = (i + 0.5) / N;                            // 노드 임계점
    var lp = seg(p, th - 0.12, th + 0.06);
    var dir = el.classList.contains("tl-left") ? -1 : 1;
    el.style.opacity = lp;
    el.style.transform = "translateX(" + (dir * 48 * (1 - lp)) + "px)";
  });
}

