  handM.style.transform = "translateX(-50%) rotate(" + (p*720) + "deg)"; // 스크럽 회전
}

var b = document.querySelector(".ho-b");
function applyReveal(p){
  b.style.transform = "translateY(" + (100 * (1 - p)) + "vh)"; // 아래→덮기
  var r = 32 * (1 - p);                                        // 카드→화면
  b.style.borderTopLeftRadius = r + "px";
  b.style.borderTopRightRadius = r + "px";
}
